export const ProtobufDescriptorInfo: MessageFns<ProtobufDescriptorInfo> = {
  encode(message: ProtobufDescriptorInfo, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.service_name !== "") {
      writer.uint32(10).string(message.service_name);
    }
    if (message.descriptor_version !== "") {
      writer.uint32(18).string(message.descriptor_version);
    }
    if (message.updated_at !== undefined) {
      Timestamp.encode(toTimestamp(message.updated_at), writer.uint32(26).fork()).join();
    }
    if (message.description !== "") {
      writer.uint32(34).string(message.description);
    }
    for (const v of message.services) {
      writer.uint32(42).string(v!);
    }
    if (message.size_bytes !== 0) {
      writer.uint32(48).uint64(message.size_bytes);
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): ProtobufDescriptorInfo {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseProtobufDescriptorInfo();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.service_name = reader.string();
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.descriptor_version = reader.string();
          continue;
        }
        case 3: {
          if (tag !== 26) {
            break;
          }

          message.updated_at = fromTimestamp(Timestamp.decode(reader, reader.uint32()));
          continue;
        }
        case 4: {
          if (tag !== 34) {
            break;
          }

          message.description = reader.string();
          continue;
        }
        case 5: {
          if (tag !== 42) {
            break;
          }

          message.services.push(reader.string());
          continue;
        }
        case 6: {
          if (tag !== 48) {
            break;
          }

          message.size_bytes = longToNumber(reader.uint64());
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): ProtobufDescriptorInfo {
    return {
      service_name: isSet(object.service_name) ? globalThis.String(object.service_name) : "",
      descriptor_version: isSet(object.descriptor_version) ? globalThis.String(object.descriptor_version) : "",
      updated_at: isSet(object.updated_at) ? fromJsonTimestamp(object.updated_at) : undefined,
      description: isSet(object.description) ? globalThis.String(object.description) : "",
      services: globalThis.Array.isArray(object?.services) ? object.services.map((e: any) => globalThis.String(e)) : [],
      size_bytes: isSet(object.size_bytes) ? globalThis.Number(object.size_bytes) : 0,
    };
  },

  toJSON(message: ProtobufDescriptorInfo): unknown {
    const obj: any = {};
    if (message.service_name !== "") {
      obj.service_name = message.service_name;
    }
    if (message.descriptor_version !== "") {
      obj.descriptor_version = message.descriptor_version;
    }
    if (message.updated_at !== undefined) {
      obj.updated_at = message.updated_at.toISOString();
    }
    if (message.description !== "") {
      obj.description = message.description;
    }
    if (message.services?.length) {
      obj.services = message.services;
    }
    if (message.size_bytes !== 0) {
      obj.size_bytes = Math.round(message.size_bytes);
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<ProtobufDescriptorInfo>, I>>(base?: I): ProtobufDescriptorInfo {
    return ProtobufDescriptorInfo.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<ProtobufDescriptorInfo>, I>>(object: I): ProtobufDescriptorInfo {
    const message = createBaseProtobufDescriptorInfo();
    message.service_name = object.service_name ?? "";
    message.descriptor_version = object.descriptor_version ?? "";
    message.updated_at = object.updated_at ?? undefined;
    message.description = object.description ?? "";
    message.services = object.services?.map((e) => e) || [];
    message.size_bytes = object.size_bytes ?? 0;
    return message;
  },
};

